double gettime() {
  struct timespec t;
  clock_gettime(CLOCK_REALTIME, &t);
  return t.tv_sec + t.tv_nsec * 1e-9;
}

int maximum(int a, int b, int c) {
  int k;
  if (b >= a)
    k = b;
  else
    k = a;

  if (c >= k)
    return c;
  else
    return k;
}

void needle_openmp_1(int* referrence, int* matrix, int cols, int penalty, int i, int block_width) {
  int index, index_n, index_w, index_nw;
  int temp[BLOCK_SIZE + 1][BLOCK_SIZE + 1];
  int ref[BLOCK_SIZE][BLOCK_SIZE];

  #pragma omp parallel for
  for (int tx = 0; tx < BLOCK_SIZE; tx++) {
    int b_index_x = i - 1 - tx;
    int b_index_y = tx;

    index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (cols + 1);
    index_n = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (1);
    index_w = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (cols);
    index_nw = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    for (int ty = 0; ty < BLOCK_SIZE; ty++)
      ref[ty][tx] = referrence[index + cols * ty];

    temp[tx + 1][0] = matrix[index_w + cols * tx];

    temp[0][tx + 1] = matrix[index_n];

    for (int m = 0; m < BLOCK_SIZE; m++) {
      if (m >= tx) {
        int t_index_x = tx + 1;
        int t_index_y = m - tx + 1;

        temp[t_index_y][t_index_x] = maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                                              temp[t_index_y][t_index_x - 1] - penalty,
                                              temp[t_index_y - 1][t_index_x] - penalty);
      }
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
      if (m >= tx) {
        int t_index_x = tx + BLOCK_SIZE - m;
        int t_index_y = BLOCK_SIZE - tx;

        temp[t_index_y][t_index_x] = maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                                              temp[t_index_y][t_index_x - 1] - penalty,
                                              temp[t_index_y - 1][t_index_x] - penalty);
      }
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++)
      matrix[index + ty * cols] = temp[ty + 1][tx + 1];
  }
}

void needle_openmp_2(int* referrence, int* matrix, int cols, int penalty, int i, int block_width) {
  int index, index_n, index_w, index_nw;
  int temp[BLOCK_SIZE + 1][BLOCK_SIZE + 1];
  int ref[BLOCK_SIZE][BLOCK_SIZE];

  #pragma omp parallel for
  for (int tx = 0; tx < BLOCK_SIZE; tx++) {
    int b_index_x = block_width - i + tx;
    int b_index_y = block_width - tx - 1;

    index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (cols + 1);
    index_n = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (1);
    index_w = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (cols);
    index_nw = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    for (int ty = 0; ty < BLOCK_SIZE; ty++)
      ref[ty][tx] = referrence[index + cols * ty];

    temp[tx + 1][0] = matrix[index_w + cols * tx];

    temp[0][tx + 1] = matrix[index_n];

    for (int m = 0; m < BLOCK_SIZE; m++) {
      if (m >= tx) {
        int t_index_x = tx + 1;
        int t_index_y = m - tx + 1;

        temp[t_index_y][t_index_x] = maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                                              temp[t_index_y][t_index_x - 1] - penalty,
                                              temp[t_index_y - 1][t_index_x] - penalty);
      }
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
      if (m >= tx) {
        int t_index_x = tx + BLOCK_SIZE - m;
        int t_index_y = BLOCK_SIZE - tx;

        temp[t_index_y][t_index_x] = maximum(temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                                              temp[t_index_y][t_index_x - 1] - penalty,
                                              temp[t_index_y - 1][t_index_x] - penalty);
      }
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++)
      matrix[index + ty * cols] = temp[ty + 1][tx + 1];
  }
}

int main(int argc, char** argv) {
  int max_rows, max_cols, penalty;
  int* input_itemsets, *output_itemsets, *referrence;
  int size;

  if (3 == argc) {
    max_rows = atoi(argv[1]);
    max_cols = atoi(argv[1]);
    penalty = atoi(argv[2]);
  } else {
    fprintf(stderr, "Usage: %s <max_rows/max_cols> <penalty> \n", argv[0]);
    fprintf(stderr, "\t<dimension>  - x and y dimensions\n");
    fprintf(stderr, "\t<penalty> - penalty(positive integer)\n");
    exit(1);
  }

  if (atoi(argv[1]) % 16 != 0) {
    fprintf(stderr, "The dimension values must be a multiple of 16\n");
    exit(1);
  }

  max_rows += 1;
  max_cols += 1;
  referrence = (int*)malloc(max_rows * max_cols * sizeof(int));
  input_itemsets = (int*)malloc(max_rows * max_cols * sizeof(int));
  output_itemsets = (int*)malloc(max_rows * max_cols * sizeof(int));

  if (!input_itemsets)
    fprintf(stderr, "error: can not allocate memory");

  srand(7);

  for (int i = 0; max_cols > i; i++) {
    for (int j = 0; max_rows > j; j++) {
      input_itemsets[i * max_cols + j] = 0;
    }
  }

  printf("Start Needleman-Wunsch\n");

  for (int i = 1; max_rows > i; i++) {
    input_itemsets[i * max_cols] = rand() % 10 + 1;
  }
  for (int j = 1; max_cols > j; j++) {
    input_itemsets[j] = rand() % 10 + 1;
  }

  for (int i = 1; max_cols > i; i++) {
    for (int j = 1; max_rows > j; j++) {
      referrence[i * max_cols + j] = blosum62[input_itemsets[i * max_cols]][input_itemsets[j]];
    }
  }

  for (int i = 1; max_rows > i; i++)
    input_itemsets[i * max_cols] = -i * penalty;
  for (int j = 1; max_cols > j; j++)
    input_itemsets[j] = -j * penalty;

  size = max_cols * max_rows;

  int block_width = (max_cols - 1) / BLOCK_SIZE;

  printf("Processing top-left matrix\n");
  for (int i = 1; block_width >= i; i++) {
    needle_openmp_1(referrence, input_itemsets, max_cols, penalty, i, block_width);
  }
  printf("Processing bottom-right matrix\n");
  for (int i = block_width - 1; 1 <= i; i--) {
    needle_openmp_2(referrence, input_itemsets, max_cols, penalty, i, block_width);
  }

  free(referrence);
  free(input_itemsets);
  free(output_itemsets);

  return EXIT_SUCCESS;
}
